mapper.select:
SELECT id, level_id, barcode, barcode_type, is_primary, valid_from, valid_to, status, deleted, created_at, updated_at, created_by, updated_by FROM barcode WHERE deleted = 0
AND barcode LIKE CONCAT('%', #{keyword}, '%')
AND level_id = #{levelId}
AND status = #{status}
ORDER BY created_at DESC, id DESC
